lurek.timer = {}

--- A Lua-exposed event scheduler that fires callbacks after timed delays or frame counts, with support for repeating intervals, named entries, pausing, and time-scaling.
---@class LScheduler
LScheduler = {}

--- Schedules a one-shot callback to fire after the given delay in seconds. Returns an event ID that can be used to cancel, pause, or query the event.
---@param delay number Time in seconds before the callback fires.
---@param func function Callback to invoke when the delay elapses.
---@return number Unique event ID for this scheduled callback.
function LScheduler:after(delay, func) end

--- Schedules a one-shot callback to fire after the given number of frames. Returns an event ID for management.
---@param n number Number of frames to wait before the callback fires.
---@param func function Callback to invoke when the frame count elapses.
---@return number Unique event ID for this scheduled callback.
function LScheduler:afterFrames(n, func) end

--- Schedules a named one-shot callback after a delay in seconds. If a callback with the same name already exists, the old one is cancelled and replaced. Useful for debouncing or resettable delays.
---@param name string Unique name for this scheduled event.
---@param delay number Time in seconds before the callback fires.
---@param func function Callback to invoke when the delay elapses.
---@return number Unique event ID for this scheduled callback.
function LScheduler:afterNamed(name, delay, func) end

--- Cancels a scheduled event by its ID. Returns true if the event was found and removed, false if it did not exist.
---@param id number Event ID returned by after, every, or their variants.
---@return boolean True if the event was found and cancelled.
function LScheduler:cancel(id) end

--- Cancels all scheduled events in this scheduler and frees their callbacks. Returns the number of events that were removed.
---@return number Count of events that were cancelled.
function LScheduler:cancelAll() end

--- Cancels a named scheduled event. Returns true if the named event was found and removed.
---@param name string The name used when scheduling with afterNamed or everyNamed.
---@return boolean True if the named event was found and cancelled.
function LScheduler:cancelNamed(name) end

--- Schedules a repeating callback that fires at a fixed interval in seconds. Pass a positive count to limit repetitions, or omit/pass -1 to repeat indefinitely.
---@param interval number Time in seconds between each invocation.
---@param func function Callback to invoke on each interval tick.
---@param count? number Maximum number of times to fire. Defaults to -1 (infinite).
---@return number Unique event ID for this repeating callback.
function LScheduler:every(interval, func, count) end

--- Schedules a repeating callback that fires every N frames. Pass a positive count to limit repetitions, or omit/pass -1 to repeat indefinitely.
---@param n number Number of frames between each invocation.
---@param func function Callback to invoke on each frame-interval tick.
---@param count? number Maximum number of times to fire. Defaults to -1 (infinite).
---@return number Unique event ID for this repeating callback.
function LScheduler:everyFrames(n, func, count) end

--- Schedules a named repeating callback at a fixed interval. If a callback with the same name already exists, the old one is cancelled and replaced. Useful for restartable periodic effects like health regeneration or status ticks.
---@param name string Unique name for this repeating event.
---@param interval number Time in seconds between each invocation.
---@param func function Callback to invoke on each interval tick.
---@param count? number Maximum number of times to fire. Defaults to -1 (infinite).
---@return number Unique event ID for this repeating callback.
function LScheduler:everyNamed(name, interval, func, count) end

--- Returns the total number of active scheduled events in this scheduler.
---@return number Count of active events.
function LScheduler:getCount() end

--- Returns the interval duration in seconds for a repeating event. The first return value indicates whether the event was found; the second is the interval (0.0 if not found).
---@param id number Event ID to query.
---@return boolean a True if the event exists.
---@return number b Interval in seconds, or 0.0 if not found.
function LScheduler:getInterval(id) end

--- Returns the remaining time in seconds before the event fires. The first return value indicates whether the event was found; the second is the remaining time (0.0 if not found).
---@param id number Event ID to query.
---@return boolean a True if the event exists.
---@return number b Remaining time in seconds, or 0.0 if not found.
function LScheduler:getRemaining(id) end

--- Returns the remaining repeat count for a repeating event. The first return value indicates whether the event was found; the second is the count (0 if not found). A value of -1 means infinite repeats.
---@param id number Event ID to query.
---@return boolean a True if the event exists.
---@return number b Remaining repeat count, or 0 if not found.
function LScheduler:getRepeatCount(id) end

--- Returns the current time scale multiplier for this scheduler.
---@return number Current time scale (1.0 = normal speed).
function LScheduler:getTimeScale() end

--- Returns true if the scheduler has no active events.
---@return boolean True when no events are scheduled.
function LScheduler:isEmpty() end

--- Checks whether a scheduled event is currently paused.
---@param id number Event ID to check.
---@return boolean True if the event is paused, false if running or not found.
function LScheduler:isPaused(id) end

--- Checks whether a named scheduled event is currently paused.
---@param name string The name used when scheduling.
---@return boolean True if the named event is paused.
function LScheduler:isPausedNamed(name) end

--- Pauses a scheduled event so it stops accumulating time. Returns true if the event was found and paused.
---@param id number Event ID to pause.
---@return boolean True if the event exists and was paused.
function LScheduler:pause(id) end

--- Pauses a named scheduled event. Returns true if the named event was found and paused.
---@param name string The name used when scheduling.
---@return boolean True if the named event exists and was paused.
function LScheduler:pauseNamed(name) end

--- Resets the elapsed time of a scheduled event back to zero, restarting its delay or interval countdown. Returns true if the event was found and reset.
---@param id number Event ID to reset.
---@return boolean True if the event was found and reset.
function LScheduler:resetEvent(id) end

--- Resumes a previously paused event so it continues accumulating time. Returns true if the event was found and resumed.
---@param id number Event ID to resume.
---@return boolean True if the event exists and was resumed.
function LScheduler:resume(id) end

--- Resumes a previously paused named event. Returns true if the named event was found and resumed.
---@param name string The name used when scheduling.
---@return boolean True if the named event exists and was resumed.
function LScheduler:resumeNamed(name) end

--- Changes the interval duration in seconds for an existing repeating event. Returns true if the event was found and updated.
---@param id number Event ID of the repeating event.
---@param interval number New interval duration in seconds.
---@return boolean True if the event was found and its interval updated.
function LScheduler:setInterval(id, interval) end

--- Sets the time scale multiplier for this scheduler. A value of 2.0 makes events fire twice as fast; 0.5 makes them fire at half speed. Does not affect frame-based events.
---@param scale number Time scale multiplier (1.0 = normal speed).
---@return nil No value is returned.
function LScheduler:setTimeScale(scale) end

--- Returns the type name of this object as a string.
---@return string Always "LScheduler".
function LScheduler:type() end

--- Checks whether this object matches the given type name. Accepts "LScheduler" or "Object".
---@param name string Type name to check against.
---@return boolean True if the name matches.
function LScheduler:typeOf(name) end

--- Advances all time-based events by dt seconds, fires any callbacks whose delay has elapsed, and cleans up completed one-shot events. Call this once per frame with delta time. Returns the number of callbacks that fired.
---@param dt number Delta time in seconds since the last update.
---@return number Count of callbacks that fired during this update.
function LScheduler:update(dt) end

--- Advances all frame-based events by one frame, fires any callbacks whose frame count has been reached, and cleans up completed one-shot events. Call this once per frame. Returns the number of callbacks that fired.
---@return number Count of callbacks that fired during this frame update.
function LScheduler:updateFrames() end

--- Schedules a one-shot callback based on real (wall-clock) time, unaffected by game pausing or time scaling. Use for UI fade-outs, notifications, or anything that should run on real time.
---@param delay number Real-time delay in seconds before the callback fires.
---@param func function Callback to invoke when the real-time deadline is reached.
---@return nil No return value.
lurek.timer.afterReal = function(delay, func) end

--- Creates a scheduler pre-loaded with a sequence of delayed callbacks. Each step is a table with an optional `delay` (seconds) and optional `func` (callback). Delays accumulate so each step fires after the sum of all preceding delays. Returns the scheduler for manual update calls.
---@param steps table Array of step tables, each with optional fields `delay` (number) and `func` (function).
---@return LScheduler A new scheduler pre-loaded with the chained events.
lurek.timer.chain = function(steps) end

--- Returns the smoothed average delta time in seconds over a recent window of frames. More stable than getDelta for display or adaptive logic.
---@return number Average delta time in seconds.
lurek.timer.getAverageDelta = function() end

--- Returns the time in seconds elapsed since the last frame. Use this to make movement and animations frame-rate independent.
---@return number Delta time in seconds.
lurek.timer.getDelta = function() end

--- Returns the current frames-per-second count. Useful for performance monitoring overlays and debug HUDs.
---@return number Current FPS.
lurek.timer.getFPS = function() end

--- Returns the total number of frames rendered since the engine started.
---@return number Total frame count.
lurek.timer.getFrameCount = function() end

--- Returns high-resolution elapsed time in seconds since engine start. Useful for precise benchmarking and profiling.
---@return number Elapsed time in seconds with sub-microsecond precision.
lurek.timer.getMicroTime = function() end

--- Returns the fixed timestep used for physics simulation in seconds. The default is typically 1/60.
---@return number Fixed physics delta time in seconds.
lurek.timer.getPhysicsDelta = function() end

--- Returns the maximum number of physics steps allowed per frame. Prevents the spiral of death when the game runs slowly.
---@return number Maximum physics steps per frame.
lurek.timer.getPhysicsMaxSteps = function() end

--- Returns an exponentially smoothed delta time in seconds, reducing frame-to-frame jitter. Call once per frame for consistent results. The smoothing factor is set via setSmoothingFactor.
---@return number Smoothed delta time in seconds.
lurek.timer.getSmoothedDelta = function() end

--- Returns the total elapsed game time in seconds since the engine started. Useful for time-based animations, effects, and shader uniforms.
---@return number Total elapsed time in seconds.
lurek.timer.getTime = function() end

--- Creates a new LScheduler instance for managing timed and frame-based callbacks independently from the global timer. Each scheduler has its own time scale and event list.
---@return LScheduler A new scheduler object.
lurek.timer.newScheduler = function() end

--- Sets the fixed timestep for physics simulation. Clamped between 1/240 and 1/10 seconds. Lower values increase accuracy but cost more CPU.
---@param dt number Desired fixed delta time in seconds.
---@return nil No return value.
lurek.timer.setPhysicsDelta = function(dt) end

--- Sets the maximum number of physics steps allowed per frame. Clamped between 1 and 64. Higher values improve accuracy under lag but cost more CPU.
---@param n number Maximum physics steps per frame.
---@return nil No return value.
lurek.timer.setPhysicsMaxSteps = function(n) end

--- Sets the exponential smoothing factor used by getSmoothedDelta. Lower values produce smoother (more lagged) results; higher values track changes faster. Clamped to [0.01, 1.0].
---@param alpha number Smoothing factor between 0.01 and 1.0.
---@return nil No return value.
lurek.timer.setSmoothingFactor = function(alpha) end

--- Blocks the current thread for the given number of seconds. Use sparingly — this halts the entire game loop. Intended for loading screens or synchronization.
---@param seconds number Duration to sleep in seconds.
---@return nil No return value.
lurek.timer.sleep = function(seconds) end

--- Advances the internal clock by one tick and returns the delta time for that tick. Typically called by the engine loop; game scripts rarely need this.
---@return number Delta time in seconds for the step.
lurek.timer.step = function() end

--- Checks all real-time timers and fires any whose deadline has passed. Returns the number of callbacks that fired. Call this once per frame after afterReal scheduling.
---@return number Count of real-time callbacks that fired.
lurek.timer.tickRealTimers = function() end

--- Checks all pending waitSeconds and waitFrames coroutines, resumes any whose deadline or frame target has been reached, and cleans up completed entries. Returns the number of coroutines that were resumed. Call once per frame.
---@return number Count of coroutines resumed.
lurek.timer.tickWaits = function() end

--- Yields the current coroutine for the given number of frames. Must be called from within a coroutine. The coroutine is resumed automatically when tickWaits is called and the target frame count has been reached.
---@param frames number Number of frames to wait.
---@return nil No return value.
lurek.timer.waitFrames = function(frames) end

--- Yields the current coroutine for the given number of real-time seconds. Must be called from within a coroutine. The coroutine is resumed automatically when tickWaits is called and the deadline has passed.
---@param seconds number Real-time seconds to wait.
---@return nil No return value.
lurek.timer.waitSeconds = function(seconds) end

---@class lurek.tween
lurek.tween = {}

--- Lua-exposed spring physics simulation that smoothly animates table fields toward target values with configurable stiffness and damping.
---@class LSpring
LSpring = {}

--- Cancels this spring animation and cleans up the on-settle callback if one was registered.
---@return nil No value is returned.
function LSpring:cancel() end

--- Returns the current position of the given spring axis, or `nil` if the axis does not exist.
---@param field string Name of the axis to query.
---@return LuaValue Current position value, or nil when the axis does not exist.
function LSpring:getPosition(field) end

--- Returns whether this spring is still actively animating.
---@return boolean `true` if active.
function LSpring:isActive() end

--- Returns whether all spring axes have reached their targets within the precision threshold.
---@return boolean `true` if the spring has settled.
function LSpring:isSettled() end

--- Sets the spring damping for all axes. Higher values reduce oscillation and overshoot.
---@param value number Damping coefficient (default 10).
---@return nil No value is returned.
function LSpring:setDamping(value) end

--- Sets the spring stiffness for all axes. Higher values make the spring snap faster.
---@param value number Stiffness coefficient (default 100).
---@return nil No value is returned.
function LSpring:setStiffness(value) end

--- Changes the spring target values for one or more axes. Re-activates the spring if it was settled.
---@param fields table Key-value pairs mapping axis names to new target values.
---@return nil No value is returned.
function LSpring:setTarget(fields) end

--- Returns the type name of this object.
---@return string Always `"LSpring"`.
function LSpring:type() end

--- Checks whether this object matches the given type name.
---@param name string Type name to check against (`"LSpring"` or `"Object"`).
---@return boolean `true` if the name matches.
function LSpring:typeOf(name) end

--- Manually advances this spring by the given delta time and writes updated positions to the target table. Returns `true` if still animating, `false` if settled.
---@param dt number Delta time in seconds.
---@return boolean `true` if the spring is still moving, `false` if settled.
function LSpring:update(dt) end

--- Creates and starts a property tween that smoothly interpolates numeric fields on the target table over the given duration.
---@class LTween
LTween = {}

--- Yields the current coroutine until this tween completes or is cancelled. Must be called from inside a coroutine.
---@return nil No return value.
function LTween:await() end

--- Cancels this tween immediately, fires the onCancel callback if set, and resumes any coroutines waiting on it.
---@return nil No return value.
function LTween:cancel() end

--- Returns the total duration of this tween in seconds.
---@return number Total duration.
function LTween:getDuration() end

--- Returns the number of seconds that have elapsed since the tween started.
---@return number Elapsed time in seconds.
function LTween:getElapsed() end

--- Returns an array of field names being tweened on the target table.
---@return table Array of field name strings.
function LTween:getFields() end

--- Returns the eased progress of this tween as a value from 0.0 to 1.0.
---@return number Eased progress ratio.
function LTween:getProgress() end

--- Returns the number of seconds remaining until this tween completes.
---@return number Remaining time in seconds.
function LTween:getRemaining() end

--- Returns whether this tween is still running (not cancelled or completed).
---@return boolean `true` if the tween is active.
function LTween:isActive() end

--- Sets a callback to fire when the tween is cancelled. Returns the tween for chaining.
---@param f function Callback fired when the tween is cancelled.
---@return LTween The same tween handle for chaining.
function LTween:onCancel(f) end

--- Sets a callback to fire when the tween completes. Returns the tween for chaining.
---@param f function Callback fired when the tween finishes.
---@return LTween The same tween handle for chaining.
function LTween:onComplete(f) end

--- Sets a callback to fire every frame while the tween is active. Returns the tween for chaining.
---@param f function Callback fired each frame with the current progress `t` (0..1).
---@return LTween The same tween handle for chaining.
function LTween:onUpdate(f) end

--- Pauses this tween so it stops advancing until resumed.
---@return nil No value is returned.
function LTween:pause() end

--- Chainable version of `setRelative`. Returns the tween for fluent API usage.
---@param enabled boolean `true` for relative mode, `false` for absolute.
---@return LTween The same tween handle for chaining.
function LTween:relative(enabled) end

--- Resumes a paused tween so it continues advancing.
---@return nil No value is returned.
function LTween:resume() end

--- Sets whether the tween end values are relative to the start values instead of absolute.
---@param enabled boolean `true` for relative mode, `false` for absolute.
---@return nil No value is returned.
function LTween:setRelative(enabled) end

--- Sets how many times the tween should repeat after the first play. Use -1 for infinite repeat.
---@param n number Number of additional repeats (0 = play once, -1 = infinite).
---@return nil No value is returned.
function LTween:setRepeat(n) end

--- Enables or disables yoyo mode, which reverses the tween direction on each repeat cycle.
---@param enabled boolean `true` to enable yoyo, `false` to disable.
---@return nil No value is returned.
function LTween:setYoyo(enabled) end

--- Returns the type name of this object.
---@return string Always `"LTween"`.
function LTween:type() end

--- Checks whether this object matches the given type name.
---@param name string Type name to check against (`"LTween"` or `"Object"`).
---@return boolean `true` if the name matches.
function LTween:typeOf(name) end

--- Creates a new empty parallel tween group. Add tweens with `:tween()` or `:add()`, then call `:start()` to run them simultaneously.
---@class LTweenParallel
LTweenParallel = {}

--- Adds an existing tween handle to this parallel group. The tween becomes owned by the group.
---@param tw_ud LTween The tween handle returned by `lurek.tween.tween()` to add to this group.
---@return nil No return value.
function LTweenParallel:add(tw_ud) end

--- Cancels all tweens in this parallel group immediately.
---@return nil No value is returned.
function LTweenParallel:cancel() end

--- Returns whether this parallel group is still running.
---@return boolean `true` if any tween in the group is still active.
function LTweenParallel:isActive() end

--- Sets a callback to fire when all tweens in this parallel group have finished. Returns the group for chaining.
---@param f function Function to call when all tweens in the group complete.
---@return LTweenParallel This parallel group for chaining.
function LTweenParallel:onComplete(f) end

--- Starts all tweens in this parallel group simultaneously.
---@return LTweenParallel This parallel group for chaining.
function LTweenParallel:start() end

--- Creates and adds a new tween step directly to this parallel group.
---@param duration number Duration in seconds.
---@param target table The table whose fields will be animated.
---@param fields table Key-value pairs mapping field names to target end values.
---@param easing? string Easing function name (default `"linear"`).
---@return LTweenParallel This parallel group for chaining.
function LTweenParallel:tween(duration, target, fields, easing) end

--- Returns the type name of this object.
---@return string Always `"LTweenParallel"`.
function LTweenParallel:type() end

--- Checks whether this object matches the given type name.
---@param name string Type name to check against (`"LTweenParallel"` or `"Object"`).
---@return boolean `true` if the name matches.
function LTweenParallel:typeOf(name) end

--- Creates a new empty tween sequence. Chain `.tween()`, `.delay()`, and `.callback()` steps, then call `:start()`.
---@class LTweenSequence
LTweenSequence = {}

--- Yields the current coroutine until this sequence completes or is cancelled. Must be called from inside a coroutine.
---@return nil No return value.
function LTweenSequence:await() end

--- Appends a callback step to this sequence that fires when reached during playback.
---@param f function Function called when this step is reached during playback.
---@return LTweenSequence This sequence for chaining.
function LTweenSequence:callback(f) end

--- Cancels this sequence immediately and resumes any coroutines waiting on it.
---@return nil No value is returned.
function LTweenSequence:cancel() end

--- Appends a delay step to this sequence. Optionally fires a callback when the delay elapses.
---@param seconds number Duration to wait in seconds.
---@param cb? function Optional callback fired when the delay elapses.
---@return LTweenSequence This sequence for chaining.
function LTweenSequence:delay(seconds, cb) end

--- Returns the overall progress ratio of this sequence from 0.0 to 1.0.
---@return number Progress ratio.
function LTweenSequence:getProgress() end

--- Returns whether this sequence is still running.
---@return boolean `true` if the sequence is active.
function LTweenSequence:isActive() end

--- Sets a callback to fire when the sequence finishes all steps. Returns the sequence for chaining.
---@param f function Function to call when the sequence completes.
---@return LTweenSequence This sequence for chaining.
function LTweenSequence:onComplete(f) end

--- Starts playback of this sequence from the first step.
---@return LTweenSequence This sequence for chaining.
function LTweenSequence:start() end

--- Appends a tween step to this sequence that animates numeric fields on the target table.
---@param duration number Duration in seconds.
---@param target table The table whose fields will be animated.
---@param fields table Key-value pairs mapping field names to target end values.
---@param easing? string Easing function name (default `"linear"`).
---@return LTweenSequence This sequence for chaining.
function LTweenSequence:tween(duration, target, fields, easing) end

--- Returns the type name of this object.
---@return string Always `"LTweenSequence"`.
function LTweenSequence:type() end

--- Checks whether this object matches the given type name.
---@param name string Type name to check against (`"LTweenSequence"` or `"Object"`).
---@return boolean `true` if the name matches.
function LTweenSequence:typeOf(name) end

--- Lua-exposed standalone tween state for manual interpolation without automatic property updates.
---@class LTweenState
---@field paused boolean  whether the tween is currently paused
LTweenState = {}

--- Returns whether this tween state has finished its full duration.
---@return boolean `true` if the tween has reached its end.
function LTweenState:isComplete() end

--- Linearly interpolates between two values using the current eased progress.
---@param start number Value at progress 0.
---@param finish number Value at progress 1.
---@return number Interpolated value.
function LTweenState:lerp(start, finish) end

--- Resets the tween state to the beginning so it can be replayed.
---@return nil No value is returned.
function LTweenState:reset() end

--- Returns the raw (un-eased) progress value from 0.0 to 1.0.
---@return number Linear progress ratio.
function LTweenState:t() end

--- Advances the tween state by the given delta time and returns the eased interpolation value (0..1).
---@param dt number Delta time in seconds to advance.
---@return number Eased value between 0 and 1.
function LTweenState:tick(dt) end

--- Returns the type name of this object.
---@return string Always `"LTweenState"`.
function LTweenState:type() end

--- Checks whether this object matches the given type name.
---@param name string Type name to check against (`"LTweenState"` or `"Object"`).
---@return boolean `true` if the name matches.
function LTweenState:typeOf(name) end

--- Immediately cancels all active tweens, sequences, parallels, and springs managed by the tween engine.
---@return nil No return value.
lurek.tween.cancelAll = function() end

--- Creates a one-shot delay. After the specified seconds elapse, the optional callback is invoked.
---@param seconds number Duration to wait in seconds.
---@param cb? function Optional callback fired when the delay completes.
---@return LTweenSequence A sequence handle representing the delay.
lurek.tween.delay = function(seconds, cb) end

--- Returns the total number of currently active tweens, sequences, and parallels.
---@return number Count of active tween objects.
lurek.tween.getActiveCount = function() end

--- Returns an array of all available easing function names, including both built-in and custom-registered easings.
---@return table Array of easing name strings.
lurek.tween.getEasingNames = function() end

--- Creates a standalone tween state for manual interpolation. Useful when you need eased progress without automatic property updates.
---@param duration number Duration in seconds.
---@param easing? string Easing function name (default `"linear"`).
---@return LTweenState The new tween state handle.
lurek.tween.newState = function(duration, easing) end

--- Creates a new empty parallel tween group. Add tweens with `:tween()` or `:add()`, then call `:start()` to run them simultaneously.
---@return LTweenParallel The new parallel group handle.
lurek.tween.parallel = function() end

--- Registers a custom easing function by name. The function receives a progress value (0..1) and must return an eased value.
---@param name string Unique name for the custom easing.
---@param f function Easing function `f(t) -> number` where t is 0..1.
---@return nil No return value.
lurek.tween.registerEasing = function(name, f) end

--- Creates a new empty tween sequence. Chain `.tween()`, `.delay()`, and `.callback()` steps, then call `:start()`.
---@return LTweenSequence The new sequence handle.
lurek.tween.sequence = function() end

--- Creates a spring-physics animation that smoothly drives table fields toward target values with bounce and settle behavior.
---@param target table The table whose fields will be animated by the spring.
---@param fields table Key-value pairs mapping field names to their spring target values.
---@param opts? table Optional settings: `stiffness` (default 100), `damping` (default 10), `precision` (default 0.001).
---@return LSpring The active spring handle.
lurek.tween.spring = function(target, fields, opts) end

--- Creates and starts a property tween with a different parameter order: target first, then fields, duration, easing.
---@param target table The table whose fields will be animated.
---@param fields table Key-value pairs mapping field names to their target end values.
---@param duration number Duration in seconds.
---@param easing? string Easing function name (default `"linear"`).
---@return LTween The active tween handle.
lurek.tween.to = function(target, fields, duration, easing) end

--- Creates and starts a property tween that smoothly interpolates numeric fields on the target table over the given duration.
---@param duration number Duration in seconds for the tween.
---@param target table The table whose fields will be animated.
---@param fields table Key-value pairs mapping field names to their target end values.
---@param easing? string Easing function name (default `"linear"`).
---@return LTween The active tween handle.
lurek.tween.tween = function(duration, target, fields, easing) end

--- Creates a sequence from a table of step descriptors. Each step is a table with `duration`, `target`, `fields`, optional `easing`, optional `callback`, or a `delay` key for pauses.
---@param steps table Array of step tables describing the chain.
---@return LTweenSequence The active sequence handle.
lurek.tween.tweenChain = function(steps) end

--- Creates and starts a color tween that smoothly interpolates r, g, b, and/or a fields on the target table.
---@param duration number Duration in seconds.
---@param target table The table containing color fields (`r`, `g`, `b`, `a`).
---@param color table Target color values as `{r=, g=, b=, a=}`. Only present keys are tweened.
---@param easing? string Easing function name (default `"linear"`).
---@return LTween The active tween handle.
lurek.tween.tweenColor = function(duration, target, color, easing) end

--- Advances all active tweens, sequences, parallels, and springs by the given delta time. Call once per frame.
---@param dt number Delta time in seconds since the last frame.
---@return nil No return value.
lurek.tween.update = function(dt) end

